const footerLinks = {
    COLLECTIONS: ["Victorian Jewelry", "Solitaire Jewelry", "Nature Jewelry"],
    SERVICES: ["Authentication", "Restoration", "Appraisal"],
    "Quick Links": ["Contact Us", "About Us", "Bespoke"],
};

type Category = keyof typeof footerLinks;

const getHref = (item: string, category: Category): string => {
    const slug = item.split(" ")[0].toLowerCase();

    if (category === "SERVICES") return `/services/${slug}`;
    if (category === "COLLECTIONS") return `/collections/style/${slug}`;
    if (category === "Quick Links" && item === "Bespoke") return `/book-appointment`;
    return `/${slug}`; // Default for Home, Contact, etc.
};

